import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useNavigate } from 'react-router-dom'; // Correct imports
import './App.css';
import LoginPage from './Components/Login';
import SignupPage from './Components/Signup';
import SideNav from './Components/SideNav'; // Import the SideNav component
import ChatBox from './Components/ChatBox';
import HomePage from './Components/HomePage'; // Import the HomePage component

function AppContent() {
  const [isAuthenticated, setIsAuthenticated] = useState(false); // Manage login state
  const navigate = useNavigate(); // Initialize the navigate function inside the Router context

  // Handle login success (navigate to HomePage on success)
  const login = () => {
    setIsAuthenticated(true);
    navigate('/HomePage'); // Navigate to HomePage when the user logs in
  };

  // Handle logout (simulate logout)
  const logout = () => {
    setIsAuthenticated(false);
    navigate('/Login'); // Navigate to Login page when the user logs out
  };

  return (
    <div className="App">
      <h1>J-Test</h1>

      {/* Render SideNav only if authenticated */}
      {isAuthenticated && <SideNav logout={logout} />} {/* Pass logout to SideNav */}

      <Routes>
        {/* Login Route */}
        <Route path="/Login" element={<LoginPage login={login} />} />

        {/* Signup Route */}
        <Route path="/Signup" element={<SignupPage />} />

        {/* HomePage Route */}
        <Route
          path="/HomePage"
          element={isAuthenticated ? <HomePage /> : <Navigate to="/Login" />}
        /> {/* Redirect to Login if not authenticated */}

        {/* ChatBox Route */}
        <Route path="/ChatBox" element={<ChatBox />} />

        {/* Default route - Redirect to Login if no route matches */}
        <Route path="/" element={<Navigate to="/Login" />} />
      </Routes>
    </div>
  );
}

// App component should only include the Router wrapper
function App() {
  return (
    <Router>
      <AppContent /> {/* Wrap the logic of App inside AppContent component */}
    </Router>
  );
}

export default App;
